var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이상하군요.","JPN":"おかしいですね。","ENG":"How odd.","TWN":"真奇怪。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"GPS 정보에 따르면 여기가 아르세니코 패밀리와 접선하기로 한 곳입니다만.","JPN":"GPS情報によると、ここがアルセニコファミリーと接触する場所ですが。","ENG":"According to the GPS coordinates, this is the rendezvous point agreed upon with the Arsenicos.","TWN":"根據GPS資訊，這裡就是跟阿塞妮克家族接頭的地方。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이런 전쟁터에서 만나자고 하다니 역시 휴먼들의 취향은 이해할 수 없군요.","JPN":"こんな戦場で待ち合わせをするなんて、やはりヒューマンの好みは理解できません。","ENG":"I could never understand the humans' idiosyncrasies, asking to meet in a battlefield like this.","TWN":"竟然約在這種戰場上，果然人類的思維無法理解。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"리, 리타! 가족 사이에 총부리를 들이밀 필요는 없잖니!","JPN":"リ、リタ！　家族同士で銃口を向ける必要はないじゃないか！","ENG":"R-Rita! There's no need to point guns at your family!","TWN":"麗、麗塔！家人之間沒必要舉槍相向吧！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"나도 너도 패밀리를 어떻게든 살려 보자는 거 아니냐.","JPN":"私も君も、ファミリーが生き残る術を模索しているだけだと思わないか？","ENG":"We're both just trying to do what's best for the organization.","TWN":"你和我終歸都是為了這個家族不是嗎。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SIR_NPC_NULL_NULL","text":{"KOREA":"그저 방법이 달랐을 뿐이야. 그러니까 그 총은 이제 그만 내려 놓고......!","JPN":"ただその方法が異なるだけだ。だからその銃はしまって、話を……！","ENG":"We just had different approaches. So why don't you put the gun down and—","TWN":"只不過是方法不同而已。所以，現在把槍放下……！"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......역겨운 놈. 넌 돼지 먹이로 주기도 아까워.","JPN":"……今更媚びを売る姿に反吐が出る。お前は豚の餌になることすらもったいないな。","ENG":"You disgust me. You're not even fit for pigswill.","TWN":"……噁心的傢伙，你不配。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"안면 스캔을 통한 신원 확인 완료. 의뢰인, 리타 아르세니코.","JPN":"顔面スキャンによる身元確認完了。依頼者、リタ・アルセニコ。","ENG":"Facial scan and recognition complete. Confirmed as the client, Rita Arsenico.","TWN":"面部掃描身份確認完畢。委託人，麗塔·阿塞妮克。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐지, 이건? 해적들이 쓰는 드론인가?","JPN":"なんだこれ？　海賊が使うドローンか？","ENG":"And what's this now? Some kind of pirate drone?","TWN":"這是，什麼？是海盜們使用的無人機？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"반갑습니다. 호라이즌 파이낸스의 대표이사, 호라이즌입니다.","JPN":"はじめまして。ホライズン・ファイナンスの代表取締役、ホライズンです。","ENG":"Greetings. I am Horizon, the CEO of Horizon Finance.","TWN":"見到您很高興。我是地平線金融的老闆，地平線本人。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌이라고? 너 따위 고철이?","JPN":"ホライズンだと？　この鉄くずが？","ENG":"You're Horizon? A piece of junk like you?","TWN":"地平線？一個破銅爛鐵？"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"너 따위라는 표현은 인정할 수 없군요.","JPN":"「鉄くず」という表現は認められませんね。","ENG":"I must protest this description of me.","TWN":"破銅爛鐵這個說法我不認可。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"내구성과 신뢰성을 고려했을 때, 물렁물렁한 단백질 반죽과 고철 중 무엇이 우월한지는 자명한 사실입니다.","JPN":"耐久性と信頼性を考慮すれば、ぷよぷよなタンパク質の塊と鉄、どちらが優秀なのかは明らかです。","ENG":"If you consider the durability and reliability of our respective bodies, you must concede I'm far superior to your mishmash of malleable proteins.","TWN":"考慮到耐久性和可靠性，軟綿綿蛋白質麵團和廢鐵…這兩者中哪個好不言自明。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"하긴, 주식도 인공지능 말대로 사는 세상이라지.","JPN":"まあ、株も人工知能に言われたとおりに買うご時世だし。","ENG":"I suppose A.I. controls everything nowadays, even the stock market.","TWN":"也是，現在買賣股票也全靠人工智慧了。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"평의회 눈치도 안 보고 만나겠다길래 별난 녀석이다 싶었는데, 소문대로군.","JPN":"評議会のことなんか気にせず会えると言うから変わった奴だと思ったが、噂どおりだな。","ENG":"I was wondering who'd be outrageous enough to ignore the Council and meet me... and now I see why.","TWN":"聽說你們不怕評議會，覺得很有個性，果然不同凡響。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"감상은 그 정도면 충분합니다. 호출한 용건을 듣고 싶군요.","JPN":"初対面の印象はそれぐらいで十分です。呼び出した要件をお聞きしましょう。","ENG":"That's quite enough admiring. Now tell me why you asked to see me.","TWN":"感言就到此為止，請說說你的目的。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};